bd list --type=agent --json 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
polecats = [b for b in data if 'role_type: polecat' in b.get('description','')]
if not polecats:
    print('No polecats found')
else:
    for p in polecats:
        print(f\"ID: {p['id']}, Title: {p['title']}, Status: {p['status']}\")
        desc = p.get('description','')
        for line in desc.split('\n'):
            line = line.strip()
            if any(k in line for k in ['agent_state','hook_bead','rig:']):
                print(f'  {line}')
" 2>/dev/null || echo "Parse error"

